// // This module implements a 2-to-1 multiplexer with an enable signal. When the enable (en) signal is LOW, the output (mux_out) will reflect the value of input a; when en is HIGH, mux_out will reflect the value of input b.
module top_module(
  input [3:0] a,
  input [3:0] b,
  input en,
  output reg [3:0] mux_out
);always @(*) begin
    if (en)
      mux_out = a;
    else
      mux_out = b;
  end

endmodule
